sql:
SELECT SUM(alert_count) AS total_alerts
FROM (
    SELECT COUNT(*) AS alert_count FROM weather_warnings WHERE station_id = 0
    UNION ALL
    SELECT COUNT(*) FROM weather_alerts WHERE station_id = 0
) AS combined_alerts;

SELECT radar_id, radar_station_id, radar_data, radar_type
FROM radar_data
WHERE radar_station_id = 3002 AND radar_type = 'phased array';

SELECT alert_type, alert_text
FROM weather_alerts
WHERE severity = 'medium' AND alert_status = 'active';

SELECT model_name 
FROM weather_models
WHERE model_accuracy > 95;

SELECT * 
FROM weather_alerts 
WHERE station_id = 'your_specific_station_id' AND alert_status = 'active';

